// Předpokládejme, že 'datumNarozeni' je tvoje proměnná z WeWebu
const birthDateString = variables['birth_date']; // Např. "1995-03-17"

if (!birthDateString) return 0;

const today = new Date();
const birthDate = new Date(birthDateString);

let age = today.getFullYear() - birthDate.getFullYear();
const monthDifference = today.getMonth() - birthDate.getMonth();

// Pokud je aktuální měsíc před měsícem narození, 
// nebo je to stejný měsíc, ale dnešní den je před dnem narození, odečteme rok.
if (monthDifference < 0 || (monthDifference === 0 && today.getDate() < birthDate.getDate())) {
    age--;
}

return age;

