const items = variables['4907c5ad-88b2-42e3-ae22-25ebe1a91ac6'] || [];

// Nastav si, co chceš počítat (např. "house" nebo "flat")
// Můžeš to mít i jako proměnnou z jiného pole
const targetType = "house";

const celkovyVysledek = items.reduce((sum, item) => {
    // Kontrola, zda se typ shoduje
    if (item?.['type'] === targetType) {
        const vstup = item?.['area'] || 0;
        const nasobitel = item?.['floor'] || 0;

        // Přičteme výpočet k celkové sumě
        return sum + (vstup * 40000 * nasobitel);
    }

    // Pokud typ nesedí, vrátíme aktuální sumu beze změny (přeskočíme)
    return sum;
}, 0);

return {
    result: celkovyVysledek
};
